import { Component, Element, Prop, h, Host, State, Watch } from '@stencil/core';
import { toTitleCase } from '@src/utils/kds-utils/stringUtils';
import { generateUniqueString } from '@src/utils/kds-utils/generateUniqueString';

@Component({
  tag: 'kds-tooltippable',
  styleUrl: './kds-tooltippable.css',
  shadow: false
})
export class KdsTooltippable {
  @Element() hostEl: HTMLKdsTooltippableElement;

  /** Sets the side a tooltip will appear relative to it's attached element. */
  @Prop() readonly side: 'top' | 'bottom' | 'left' | 'right' = 'bottom';
  /** Sets how the tooltip will align with it's attached element. */
  @Prop() readonly align: 'center' | 'left' | 'right' = 'center';
  /** Sets the text that will render inside the tooltip. */
  @Prop() readonly tooltipText: string;

  /** Determines if the tooltip acts as a label or description of the tooltipped element and sets proper aria attributes. */
  @Prop() readonly tooltipType!: 'label' | 'description';

  @State() currentSide: 'top' | 'bottom' | 'left' | 'right' = this.side;
  @State() currentAlign: 'center' | 'left' | 'right' = this.align;
  @State() hideTooltip: boolean = false;

  @Watch('side')
  updateSide(newSide) {
    this.currentSide = newSide;
  }

  @Watch('align')
  updateAlign(newAlign) {
    this.currentAlign = newAlign;
  }

  intersectionCount: number = 0;

  tooltipContent!: HTMLDivElement;
  tooltip!: HTMLDivElement;

  tooltipId: string = generateUniqueString();

  handleIntersect = (entries) => {
    entries.forEach((entry) => {
      this.intersectionCount++;
      if (this.intersectionCount <= 2) {
        const clientRect = entry.boundingClientRect;
        const intersectionRect = entry.intersectionRect;
        if (this.side === 'top' || this.side === 'bottom') {
          if (
            clientRect.top < intersectionRect.top &&
            clientRect.top < clientRect.bottom
          ) {
            this.currentSide = 'bottom';
          } else if (
            clientRect.bottom > intersectionRect.bottom &&
            clientRect.bottom > clientRect.top
          ) {
            this.currentSide = 'top';
          } else if (clientRect.left < intersectionRect.left) {
            this.currentAlign = 'left';
          } else if (clientRect.right > intersectionRect.right) {
            this.currentAlign = 'right';
          }
        } else if (this.side === 'left' || this.side === 'right') {
          if (clientRect.left < intersectionRect.left) {
            this.currentSide = 'right';
          } else if (clientRect.right > intersectionRect.right) {
            this.currentSide = 'left';
          }
        }
      }
    });
  };

  observer: IntersectionObserver = new IntersectionObserver(
    this.handleIntersect,
    {
      root: null,
      rootMargin: '0px',
      threshold: [0.05, 0.25, 0.5, 0.75, 1, 0]
    }
  );

  intersectionTimeout: NodeJS.Timeout;

  shouldAlignCenter() {
    if (this.currentAlign === 'center') {
      return true;
    } else if (this.currentSide === 'left' || this.currentSide === 'right') {
      return true;
    } else {
      return false;
    }
  }

  registerObserver() {
    this.hideTooltip = false;
    clearTimeout(this.intersectionTimeout);
    this.observer && this.observer.observe(this.tooltipContent);
  }

  disconnectObserver() {
    this.intersectionTimeout = setTimeout(() => {
      this.observer && this.observer.unobserve(this.tooltipContent);
      this.currentSide = this.side;
      this.currentAlign = this.align;
      this.hideTooltip = false;
      this.intersectionCount = 0;
      clearTimeout(this.intersectionTimeout);
    }, 250);
  }

  componentDidLoad() {
    const ariaType: string =
      this.tooltipType && this.tooltipType === 'label'
        ? 'aria-labelledby'
        : 'aria-describedby';
    const firstChild =
      this.hostEl.firstElementChild &&
      this.hostEl.firstElementChild.hasAttribute('slot')
        ? this.hostEl.children[1]
        : this.hostEl.firstElementChild;
    const isKdsComponent =
      firstChild &&
      window &&
      window.customElements.get(firstChild.nodeName.toLowerCase());

    isKdsComponent
      ? firstChild.setAttribute(
        `inner-${ariaType}`,
        `kds-Tooltip-${this.tooltipId}`
      )
      : firstChild &&
      firstChild.setAttribute(ariaType, `kds-Tooltip-${this.tooltipId}`);

    firstChild &&
    firstChild.addEventListener('mouseover', () => {
      this.tooltip.classList.remove('kds-Tooltip--isHidden');
    });

    firstChild &&
    firstChild.addEventListener('mouseout', () => {
      this.tooltip.classList.add('kds-Tooltip--isHidden');
    });

    firstChild &&
    firstChild.addEventListener('focusin', () => {
      this.tooltip.classList.remove('kds-Tooltip--isHidden');
    });

    firstChild &&
    firstChild.addEventListener('focusout', () => {
      this.tooltip.classList.add('kds-Tooltip--isHidden');
    });

    this.tooltipContent &&
    this.tooltipContent.addEventListener('mouseover', () => {
      this.tooltip.classList.remove('kds-Tooltip--isHidden');
    });

    this.tooltipContent &&
    this.tooltipContent.addEventListener('mouseout', () => {
      this.tooltip.classList.add('kds-Tooltip--isHidden');
    });
  }

  render() {
    return (
      <Host
        class='kds-Tooltippable'
        onMouseEnter={() => this.registerObserver()}
        onMouseLeave={() => this.disconnectObserver()}
        onFocusin={() => this.registerObserver()}
        onFocusout={() => this.disconnectObserver()}
        onKeyDown={({ key }) => {
          if (key === 'Escape') {
            this.hideTooltip = true;
          }
        }}
      >
        <slot />
        <div
          class={{
            'kds-Tooltip': true,
            [`kds-Tooltip--side${toTitleCase(this.currentSide)}`]: true,
            'kds-Tooltip--alignCenter':
              this.currentAlign === 'center' ||
              this.currentSide === 'right' ||
              this.currentSide === 'left',
            'kds-Tooltip--alignLeft':
              this.currentSide !== 'right' &&
              this.currentSide !== 'left' &&
              this.currentAlign === 'left',
            'kds-Tooltip--alignRight':
              this.currentSide !== 'right' &&
              this.currentSide !== 'left' &&
              this.currentAlign === 'right',
            'kds-Tooltip--horizontal':
              this.currentSide === 'left' || this.currentSide === 'right',
            'kds-Tooltip--vertical':
              this.currentSide === 'bottom' || this.currentSide === 'top'
          }}
          role='tooltip'
          hidden={this.hideTooltip}
          ref={(el: HTMLDivElement) => (this.tooltip = el)}
        >
          <div class='kds-Tooltip-arrowWrapper'>
            <div class='kds-Tooltip-arrow'></div>
          </div>
          <div
            class='kds-Tooltip-content'
            id={`kds-Tooltip-${this.tooltipId}`}
            ref={(el: HTMLDivElement) => (this.tooltipContent = el)}
          >
            <slot name='tooltipText' />
            {this.tooltipText}
          </div>
        </div>
      </Host>
    );
  }
}
